import type { HskUiLevel } from "@/types/library";

/**
 * Coverage report shape. Generated by `npm run hsk:coverage` and consumed
 * by the Reading Path UI. Storing this as a JSON artifact (not computed at
 * runtime) keeps the page fast even as the HSK vocabulary set grows.
 */
export interface HskLevelCoverage {
  level: HskUiLevel;

  /** Words newly introduced at this level (level-exclusive set). */
  exclusiveTotal: number;
  exclusiveCovered: number;
  exclusiveCoveragePct: number;
  exclusiveMissing: string[];

  /** All words from HSK 1 through this level (cumulative set). */
  cumulativeTotal: number;
  cumulativeCovered: number;
  cumulativeCoveragePct: number;
  cumulativeMissing: string[];

  /** Exposure stats for this level's exclusive words across all passages. */
  exposureCounts: Record<string, number>;
  singleExposureWords: string[];
  overusedWords: Array<{ word: string; count: number }>;

  passageCount: number;
}

export interface HskCoverageReport {
  generatedAt: string;
  hskSystem: string;
  levels: HskLevelCoverage[];
  /** Per-passage rollup. */
  passages: Array<{
    id: string;
    slug: string;
    hskLevel: HskUiLevel;
    chars: number;
    distinctWords: number;
    aboveLevelWords: string[];
  }>;
}
